         * Responsive 'tablet' device name.
         *
         * @deprecated 3.4.0
         */
        const RESPONSIVE_TABLET = 'tablet';
        /**
         * Responsive 'mobile' device name.
         *
         * @deprecated 3.4.0
         */
        const RESPONSIVE_MOBILE = 'mobile';
